const items = $input.all();

if (items.length === 0 || !items[0].json.id) {
  return [];
}

return items;

// Pega os dados da conversa atual do SplitInBatches
const conversaData = $('Loop Over Items').first().json;
const historico = $input.all().map(item => item.json);

let conversaFormatada = '';
let teveOrcamento = false;
let ultimoValor = null;
let ultimaMsgCliente = '';

for (const msg of historico) {
  if (msg.user_message) {
    conversaFormatada += `Cliente: ${msg.user_message}\n`;
    ultimaMsgCliente = msg.user_message;
  }
  if (msg.bot_message) {
    conversaFormatada += `Tars: ${msg.bot_message}\n`;

    const msgLower = msg.bot_message.toLowerCase();
    if (msgLower.includes('r$') || 
        msgLower.includes('orcamento') || 
        msgLower.includes('total') ||
        msgLower.includes('valor')) {
      teveOrcamento = true;

      const valorMatch = msg.bot_message.match(/R\$\s*([\d.,]+)/i);
      if (valorMatch) {
        ultimoValor = valorMatch[1];
      }
    }
  }
  conversaFormatada += '\n';
}

return {
  json: {
    conversation_id: conversaData.conversation_id,
    phone: conversaData.phone,
    nome_cliente: conversaData.nome_cliente || 'Cliente',
    loja: conversaData.loja,
    cliente: conversaData.cliente,
    schema_name: conversaData.schema_name,
    follow_up_stage: conversaData.follow_up_stage,
    historico_conversa: conversaFormatada.trim(),
    ultima_msg_cliente: ultimaMsgCliente,
    had_quote: teveOrcamento,
    ultimo_valor: ultimoValor,
    total_mensagens: historico.length
  }
};

const analise = $input.first().json.message.content.trim().toUpperCase();
const dados = $('Formata Historico').first().json;

if (analise.includes('PARAR')) {
  return {
    json: {
      ...dados,
      decisao: 'PARAR',
      motivo: 'Cliente demonstrou desinteresse'
    }
  };
}

return {
  json: {
    ...dados,
    decisao: 'CONTINUAR'
  }
};

const tokens = {
  alberto: {
    'default': '464d243c-e664-49a0-aefa-53bb68de8bbd'
  },
  marcel: {
    '199': 'ca609f35-c070-4c62-9378-0fc93224e068',
    '037': 'e7b831ab-9d0b-4744-8d04-450dafef227e',
    '179': '7fe60c26-d2a0-46fd-aeeb-b784808605b9',
    'default': 'ca609f35-c070-4c62-9378-0fc93224e068'
  }
};

const cliente = $input.first().json.cliente;
const loja = $input.first().json.loja || '';
const codigoLoja = loja.match(/^\d+/) ? loja.match(/^\d+/)[0] : 'default';

let token;
if (cliente === 'alberto') {
  token = tokens.alberto.default;
} else {
  token = tokens.marcel[codigoLoja] || tokens.marcel.default;
}

return {
  json: {
    ...$input.first().json,
    token: token,
    codigo_loja: codigoLoja
  }
};

